{
  "title": "क्यू ऑपरेशन्स",
  "group": "डेटा संरचनाएँ",
  "options": [
    {
      "text": "Enqueue और Dequeue",
      "hint": "क्यू में एक तत्व जोड़ने और निकालने के लिए उपयोग किया जाता है।"
    },
    {
      "text": "Push और Pop",
      "hint": "एक स्टैक में तत्व जोड़ने और निकालने के लिए उपयोग किया जाता है।"
    },
    {
      "text": "Peek और Top",
      "hint": "क्यू में सामने वाले तत्व को देखने के लिए उपयोग किया जाता है, जबकि Top स्टैक में उपयोग किया जाता है।"
    },
    {
      "text": "Traverse और Sort",
      "hint": "डेटा संरचनाओं में सामान्य ऑपरेशन हैं, लेकिन क्यू के लिए विशिष्ट नहीं हैं।"
    }
  ],
  "questionProse": [
    "एक क्यू के लिए दो प्राथमिक ऑपरेशन क्या हैं?"
  ],
  "explanationProse": [
    "क्यू में दो प्राथमिक ऑपरेशन हैं: Enqueue (पीछे एक तत्व जोड़ें) और Dequeue (सामने से एक तत्व निकालें)। क्यू का आधारभूत नियम FIFO (First In, First Out) होता है, जिसका अर्थ है कि जो तत्व पहले जुड़ता है, वह पहले निकलता है। Push/Pop स्टैक के लिए होते हैं जबकि Peek/Top अक्सर स्टैक या क्यू के सामने वाले तत्व को देखने के लिए उपयोग होते हैं। Traverse/Sort आम डेटा संरचना ऑपरेशन हैं लेकिन क्यू के लिए विशिष्ट नहीं हैं।"
  ]
}
